import{_ as t,c as a,o,a1 as r}from"./chunks/framework.9hXSu8bi.js";const e="/mypatterndocs/static/%E9%A2%84%E8%AD%A6%E4%BA%BA%E5%91%98%E7%AE%A1%E7%90%86%E4%BB%8B%E7%BB%8D.BJkajJ2V.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/预警人员管理.md","filePath":"zh/帮助文档/功能介绍/预警人员管理.md"}'),l={name:"zh/帮助文档/功能介绍/预警人员管理.md"},n=r('<h2 id="预警人员管理" tabindex="-1">预警人员管理 <a class="header-anchor" href="#预警人员管理" aria-label="Permalink to &quot;预警人员管理&quot;">​</a></h2><blockquote><p>预警人员管理页面用于维护接收预警通知的联系人信息，支持对人员进行增删改查以及测试通知功能。</p></blockquote><p><img src="'+e+'" alt="" data-fancybox="gallery"></p><h3 id="_1-预警人员搜索栏" tabindex="-1">1. 预警人员搜索栏 <a class="header-anchor" href="#_1-预警人员搜索栏" aria-label="Permalink to &quot;1. 预警人员搜索栏&quot;">​</a></h3><ul><li><strong>名称搜索</strong>：输入姓名或部分姓名，快速查找目标预警人员。</li><li><strong>查询</strong>：点击后根据输入的关键词筛选预警人员列表。</li><li><strong>重置</strong>：清空搜索条件，恢复显示全部预警人员。</li></ul><h3 id="_2-预警人员基本信息" tabindex="-1">2. 预警人员基本信息 <a class="header-anchor" href="#_2-预警人员基本信息" aria-label="Permalink to &quot;2. 预警人员基本信息&quot;">​</a></h3><ul><li><strong>姓名</strong>：预警人员的姓名。</li><li><strong>邮件</strong>：预警人员的电子邮箱，用于接收邮件通知。</li><li><strong>手机号</strong>：预警人员的手机号码，用于接收短信通知。</li></ul><h3 id="_3-编辑预警人员" tabindex="-1">3. 编辑预警人员 <a class="header-anchor" href="#_3-编辑预警人员" aria-label="Permalink to &quot;3. 编辑预警人员&quot;">​</a></h3><ul><li><strong>新增</strong>：添加新的预警人员，填写姓名、邮件、手机号信息。</li><li><strong>邮箱测试</strong>：向该人员的邮箱发送测试邮件，验证邮件通知是否可达。</li><li><strong>短信测试</strong>：向该人员的手机发送测试短信，验证短信通知是否可达。</li><li><strong>编辑</strong>：修改当前预警人员的姓名、邮件、手机号信息。</li><li><strong>删除</strong>：从系统中移除该预警人员。</li></ul>',9),s=[n];function i(_,c,h,d,g,u){return o(),a("div",null,s)}const f=t(l,[["render",i]]);export{m as __pageData,f as default};
